object SessionTokenUtils {
    
    fun generateSimpleToken(length: Int = 32): String {
        val charPool = ('A'..'Z') + ('a'..'z') + ('0'..'9')
        val random = SecureRandom()
        return (1..length)
            .map { charPool[random.nextInt(charPool.size)] }
            .joinToString("")
    }
    
    fun generateUUIDToken(): String {
        return UUID.randomUUID().toString().replace("-", "")
    }
    
    fun generateTimestampedToken(): String {
        val timestamp = System.currentTimeMillis().toString()
        val randomPart = generateSimpleToken(16)
        return "$timestamp-$randomPart"
    }
    
    fun validateTokenFormat(token: String): Boolean {
        if (token.length != 32) return false
        return token.all { it.isLetterOrDigit() }
    }
}